import { useState } from 'react';
import { useToast } from '@/hooks/use-toast';
import { apiRequest } from '@/lib/queryClient';

export default function Newsletter() {
  const [email, setEmail] = useState('');
  const [submitting, setSubmitting] = useState(false);
  const { toast } = useToast();

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!email || !email.includes('@')) {
      toast({
        title: "Invalid email",
        description: "Please enter a valid email address.",
        variant: "destructive"
      });
      return;
    }

    setSubmitting(true);

    try {
      const response = await apiRequest(
        'POST',
        '/api/newsletter/subscribe',
        { email }
      );

      const data = await response.json();

      if (data.success) {
        toast({
          title: "Subscription successful!",
          description: "You've joined our cosmic community. Look for our newsletter soon!",
        });
        setEmail('');
      } else {
        toast({
          title: "Subscription failed",
          description: data.message || "There was an error subscribing to the newsletter. Please try again.",
          variant: "destructive"
        });
      }
    } catch (error) {
      console.error('Newsletter subscription error:', error);
      toast({
        title: "Subscription failed",
        description: "There was an error connecting to our cosmic server. Please try again later.",
        variant: "destructive"
      });
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <section className="my-16 max-w-4xl mx-auto">
      <div className="bg-gradient-to-r from-cosmic-purple/20 to-cosmic-blue/20 rounded-xl p-8 border border-space-800">
        <div className="flex flex-col md:flex-row items-center gap-8">
          <div className="flex-1">
            <h2 className="text-2xl font-space font-bold mb-3">Join Our Cosmic Community</h2>
            <p className="text-space-100 mb-4">
              Subscribe to our newsletter for weekly cosmic insights, meditation guides, and exclusive content.
            </p>

            <form className="flex flex-col sm:flex-row gap-3" onSubmit={handleSubmit}>
              <input 
                type="email" 
                placeholder="Your email address"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                className="flex-grow bg-space-950 bg-opacity-50 border border-space-700 focus:border-cosmic-pink rounded-md px-4 py-2 text-space-100 placeholder-space-600 focus:outline-none"
              />

              <button 
                type="submit"
                disabled={submitting}
                className={`${submitting ? 'bg-cosmic-pink/70' : 'bg-cosmic-pink hover:bg-pink-600'} text-white font-medium py-2 px-6 rounded-md transition-colors whitespace-nowrap`}
              >
                {submitting ? 'Subscribing...' : 'Subscribe'}
              </button>
            </form>
          </div>

          <div className="flex-shrink-0 w-24 h-24 relative">
            <div className="w-24 h-24 rounded-full bg-cosmic-purple/20 border border-cosmic-purple/40 flex items-center justify-center animate-float">
              <i className="ri-mail-star-line text-4xl text-cosmic-pink"></i>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}

client/src/components/PayPalButton.tsx.content:
import { useEffect, useState } from 'react';
import { 
  PayPalScriptProvider, 
  PayPalButtons,
  usePayPalScriptReducer
} from '@paypal/react-paypal-js';
import { useToast } from '../hooks/use-toast';
import { Loader2 } from 'lucide-react';

interface PayPalButtonWrapperProps {
  showSpinner?: boolean;
  amount: string;
  onApprove: (data: { orderID: string }) => Promise<void>;
  onError: (err: any) => void;
  onCancel: () => void;
}

// This component renders the PayPal button wrapped in necessary context
const ButtonWrapper = ({ 
  showSpinner, 
  amount, 
  onApprove, 
  onError, 
  onCancel 
}: PayPalButtonWrapperProps) => {

  const [{ isPending }] = usePayPalScriptReducer();

  return (
    <>
      {(showSpinner && isPending) && (
        <div className="flex justify-center py-4">
          <Loader2 className="h-6 w-6 animate-spin text-gray-300" />
        </div>
      )}

      <PayPalButtons
        style={{ 
          color: "blue",
          shape: "pill",
          label: "subscribe",
          height: 46
        }}
        disabled={false}
        createOrder={(data, actions) => {
          return actions.order.create({
            intent: "CAPTURE",
            purchase_units: [
              {
                amount: {
                  value: amount,
                  currency_code: 'USD'
                },
                description: "Cosmic Channeling Premium Monthly Subscription"
              }
            ],
            application_context: {
              brand_name: 'Cosmic Channeling',
              user_action: 'PAY_NOW'
            }
          });
        }}
        onApprove={async (data, actions) => {
          if (actions.order) {
            await actions.order.capture();
            await onApprove(data);
          }
        }}
        onCancel={onCancel}
        onError={onError}
      />
    </>
  );
};

interface PayPalButtonProps {
  amount: string;
  onSuccess: (orderId: string) => void;
  onError?: (error: any) => void;
  onCancel?: () => void;
}

export default function PayPalButton({ 
  amount, 
  onSuccess,
  onError,
  onCancel
}: PayPalButtonProps) {
  const [scriptLoaded, setScriptLoaded] = useState(false);
  const { toast } = useToast();

  const clientId = import.meta.env.VITE_PAYPAL_CLIENT_ID || '';

  useEffect(() => {
    if (!clientId) {
      console.error('PayPal client ID is missing!');
    } else {
      setScriptLoaded(true);
    }
  }, [clientId]);

  if (!scriptLoaded) {
    return (
      <div className="flex justify-center py-4">
        <Loader2 className="h-6 w-6 animate-spin text-gray-300" />
      </div>
    );
  }

  return (
    <PayPalScriptProvider
      options={{
        clientId: clientId,
        currency: "USD",
        intent: "capture"
      }}
    >
      <ButtonWrapper
        showSpinner={true}
        amount={amount}
        onApprove={async (data) => {
          try {
            await onSuccess(data.orderID);
          } catch (error) {
            console.error("Error in onApprove:", error);
            if (onError) onError(error);
          }
        }}
        onError={(err) => {
          console.error("PayPal error:", err);
          toast({
            title: "Payment Error",
            description: "There was a problem with your payment. Please try again.",
            variant: "destructive"
          });
          if (onError) onError(err);
        }}
        onCancel={() => {
          toast({
            title: "Payment Cancelled",
            description: "Your payment was cancelled.",
            variant: "default"
          });
          if (onCancel) onCancel();
        }}
      />
    </PayPalScriptProvider>
  );
}

