import { useState, useEffect } from "react";
import { useAuth } from "../hooks/use-auth";
import { useLocation } from "wouter";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from "@/components/ui/card";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { useToast } from "@/hooks/use-toast";
import StarBackground from "@/components/ui/StarBackground";
import { Separator } from "@/components/ui/separator";
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert";
import { Lock, Star, Book } from "lucide-react";
import { apiRequest, queryClient } from "@/lib/queryClient";

export default function AuthPage() {
  const [location, setLocation] = useLocation();
  const { user, loginMutation, registerMutation } = useAuth();
  const { toast } = useToast();
  const [isProcessingOAuth, setIsProcessingOAuth] = useState(false);

  const [referringPath, setReferringPath] = useState<string | null>(null);

  useEffect(() => {
    // Check for query parameters
    const urlParams = new URLSearchParams(window.location.search);

    // Check if user was redirected from a protected route
    if (urlParams.has('from')) {
      setReferringPath(urlParams.get('from'));
    }

    // Check for OAuth callback success
    if (urlParams.has('auth') && urlParams.get('auth') === 'success') {
      // Refresh the user data from the server
      apiRequest('GET', '/api/user')
        .then(response => {
          if (response.ok) {
            return response.json();
          }
          throw new Error('Failed to get user data');
        })
        .then(userData => {
          toast({
            title: "Login Successful",
            description: "You've logged in with Google!",
          });
        })
        .catch(error => {
          console.error('Error refreshing user data after OAuth:', error);
          toast({
            title: "Authentication Error",
            description: "Something went wrong with the authentication process",
            variant: "destructive"
          });
        });

      // Clean up the URL
      window.history.replaceState({}, document.title, window.location.pathname);
    }

    // Check for error parameters
    if (urlParams.has('error')) {
      const error = urlParams.get('error');
      let errorMessage = "Authentication failed";

      if (error === 'auth_error') {
        errorMessage = "Google authentication error. Please try again.";
      } else if (error === 'auth_failed') {
        errorMessage = "Google authentication failed. Please try another method.";
      } else if (error === 'login_error') {
        errorMessage = "Error logging in. Please try again.";
      }

      toast({
        title: "Authentication Error",
        description: errorMessage,
        variant: "destructive"
      });

      // Clean up the URL
      window.history.replaceState({}, document.title, window.location.pathname);
    }
  }, [toast]);

  // Redirect to home if already logged in
  if (user) {
    setLocation("/");
    return null;
  }

  const handleGoogleLogin = () => {
    // Show processing state
    setIsProcessingOAuth(true);
    toast({
      title: "Google Sign-In",
      description: "Opening Google authentication...",
    });

    // Open Google sign-in in a new browser window to avoid the disallowed_useragent issue
    const googleAuthUrl = '/api/auth/google';
    const width = 500;
    const height = 600;
    const left = window.screenX + (window.outerWidth - width) / 2;
    const top = window.screenY + (window.outerHeight - height) / 2.5;
    const features = `width=${width},height=${height},left=${left},top=${top},status=yes,scrollbars=yes`;

    // Open the Google Auth popup
    const authWindow = window.open(googleAuthUrl, 'googleAuthPopup', features);

    if (!authWindow) {
      setIsProcessingOAuth(false);
      toast({
        title: "Error",
        description: "Popup was blocked. Please allow popups for this site.",
        variant: "destructive"
      });
      return;
    }

    // Handle the auth window close event
    const checkPopup = setInterval(() => {
      if (!authWindow || authWindow.closed) {
        clearInterval(checkPopup);
        setIsProcessingOAuth(false);

        // The popup was closed, check if authentication succeeded
        apiRequest('GET', '/api/user')
          .then(response => {
            if (response.ok) {
              // User is logged in, refresh the page
              toast({
                title: "Success",
                description: "You've been successfully authenticated!",
              });
              queryClient.invalidateQueries({ queryKey: ["/api/user"] })
                .then(() => {
                  setLocation('/');
                });
            } else {
              // Not logged in after popup closed
              toast({
                title: "Authentication Failed",
                description: "Google sign-in was not completed. Please try again.",
                variant: "destructive"
              });
            }
          })
          .catch(err => {
            console.error('Error checking auth status:', err);
            toast({
              title: "Error",
              description: "Failed to verify authentication status.",
              variant: "destructive"
            });
          });
      }
    }, 1000);
  };

  return (
    <div className="min-h-screen flex flex-col md:flex-row">
      {/* Form column */}
      <div className="w-full md:w-1/2 px-4 py-12 flex flex-col justify-center items-center relative">
        <StarBackground />
        <Card className="w-full max-w-md bg-black/50 backdrop-blur-md border-purple-600/30">
          <CardHeader className="space-y-1">
            <CardTitle className="text-2xl font-bold text-center">Cosmic Channeling</CardTitle>
            <CardDescription className="text-center">
              Enter your sacred space to explore the cosmos
            </CardDescription>

            {referringPath && (
              <Alert className="mx-4 mt-2 bg-purple-900/20 border-purple-500/30">
                <Lock className="h-4 w-4 text-purple-400" />
                <AlertTitle>Protected Feature</AlertTitle>
                <AlertDescription>
                  {referringPath === '/journal' ? (
                    <>You need to sign in to access your personal Cosmic Journal.</>
                  ) : referringPath === '/tools' ? (
                    <>You need to sign in to access your Dream Interpreter and save your interpretations.</>
                  ) : (
                    <>You need to sign in to access this feature.</>
                  )}
                </AlertDescription>
              </Alert>
            )}
          </CardHeader>
          <Tabs defaultValue="login" className="w-full">
            <TabsList className="grid w-full grid-cols-2">
              <TabsTrigger value="login">Login</TabsTrigger>
              <TabsTrigger value="register">Register</TabsTrigger>
            </TabsList>
            <TabsContent value="login">
              <LoginForm handleGoogleLogin={handleGoogleLogin} isProcessingOAuth={isProcessingOAuth} />
            </TabsContent>
            <TabsContent value="register">
              <RegisterForm handleGoogleLogin={handleGoogleLogin} isProcessingOAuth={isProcessingOAuth} />
            </TabsContent>
          </Tabs>
        </Card>
      </div>

      {/* Hero column */}
      <div className="w-full md:w-1/2 bg-purple-900 p-12 flex flex-col justify-center relative overflow-hidden">
        <div className="absolute inset-0 bg-[url('/images/cosmos.jpg')] bg-cover bg-center opacity-20"></div>
        <div className="relative z-10">
          <h1 className="text-4xl md:text-5xl font-bold mb-6">Begin Your Cosmic Journey</h1>
          <p className="text-xl mb-8">
            Unlock the secrets of the universe, explore your spiritual essence, and discover cosmic wisdom.
          </p>
          <div className="space-y-4">
            <FeatureItem title="Cosmic Exploration" description="Explore celestial bodies and their spiritual significance" />
            <FeatureItem title="Dream Interpretation" description="Understand the cosmic messages in your dreams" />
            <FeatureItem title="Meditation Tools" description="Connect with universal energy through guided practices" />
            <FeatureItem title="Spiritual Insights" description="Receive daily cosmic wisdom tailored to your journey" />
          </div>
        </div>
      </div>
    </div>
  );
}

function LoginForm({ handleGoogleLogin, isProcessingOAuth }: { handleGoogleLogin: () => void, isProcessingOAuth: boolean }) {
  const [username, setUsername] = useState("");
  const [password, setPassword] = useState("");
  const { loginMutation } = useAuth();
  const { toast } = useToast();
  const [, setLocation] = useLocation();

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!username || !password) {
      toast({
        title: "Error",
        description: "Please enter both username and password",
        variant: "destructive"
      });
      return;
    }

    try {
      await loginMutation.mutateAsync({ username, password });
      setLocation("/");
    } catch (error: any) {
      console.error("Login error:", error);
      const errorMessage = error.response?.data?.message || error.message || "Login failed";
      toast({
        title: "Login Error",
        description: errorMessage,
        variant: "destructive"
      });
    }
  };

  return (
    <form onSubmit={handleSubmit}>
      <CardContent className="space-y-4">
        <div className="space-y-2">
          <Label htmlFor="login-username">Username</Label>
          <Input 
            id="login-username" 
            placeholder="cosmicexplorer" 
            value={username}
            onChange={(e) => setUsername(e.target.value)}
            required
          />
        </div>
        <div className="space-y-2">
          <Label htmlFor="login-password">Password</Label>
          <Input 
            id="login-password" 
            type="password" 
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            required
          />
        </div>
      </CardContent>
      <CardFooter className="flex flex-col space-y-4">
        <Button 
          type="submit" 
          className="w-full" 
          disabled={loginMutation.isPending}
        >
          {loginMutation.isPending ? "Authenticating..." : "Login"}
        </Button>

        <div className="relative">
          <div className="absolute inset-0 flex items-center">
            <span className="w-full border-t border-gray-400" />
          </div>
          <div className="relative flex justify-center text-xs uppercase">
            <span className="bg-black px-2 text-gray-400">Or continue with</span>
          </div>
        </div>

        <Button 
          type="button" 
          variant="outline" 
          className="w-full"
          onClick={handleGoogleLogin}
          disabled={isProcessingOAuth}
        >
          {isProcessingOAuth ? (
            <>
              <span className="mr-2 h-4 w-4 animate-spin rounded-full border-2 border-b-transparent border-current"></span>
              Authenticating with Google...
            </>
          ) : (
            <>
              <svg className="mr-2 h-4 w-4" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" fill="#4285F4" />
