              target="_blank" 
              rel="noopener noreferrer"
              className="text-[#7E22CE] hover:text-[#EC4899] text-sm flex items-center transition-colors"
            >
              Read more <i className="ri-external-link-line ml-1"></i>
            </a>
          </div>
        </div>
      </CardContent>
    </Card>
  );
};

const Explore = () => {
