                  {tradition.sacredTexts.map((text, index) => (
                    <Badge key={index} variant="outline" className="text-xs">
                      {text}
                    </Badge>
                  ))}
                </div>
              </CardContent>
            </Card>
          </div>

          {tradition.quotes.length > 0 && (
