type CelestialEvent = {
  id: string;
  name: string;
  date: Date;
  description: string;
  significance: string;
  recommendations: string[];
};

// Sample cosmic signals
const sampleSignals: Signal[] = [
  {
    id: '1',
    type: 'synchronicity',
