                <Badge 
                  variant="outline"
                  className={`cursor-pointer ${activeSignalTab === 'energy' 
                    ? 'bg-purple-900/50 text-purple-300 border-purple-500/50' 
                    : 'bg-black/40 hover:bg-gray-900 text-gray-400 hover:text-gray-300'}`}
